import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

export default function Widget() {
  const { currentRun, routeSegments } = response.data.data;
  const clipPathId = React.useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} color="primary">
              Current Run
            </Typography>
            <Typography variant="body1" sx={{ mt: 0.5 }}>
              Pace: {currentRun.pace}
            </Typography>
            <Typography variant="body1">
              Distance: {currentRun.distance}
            </Typography>
            <Typography variant="body1">
              Elevation Gain: {currentRun.elevationGain}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: routeSegments.map(segment => parseFloat(segment.pace.split(' ')[0].replace(':', '.'))),
                  color: '#FF5722',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: routeSegments.map(segment => segment.segment),
                  id: 'segments',
                },
              ]}
              yAxis={[{ id: 'pace', label: 'Pace (min/km)' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="segments"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="pace"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Grid container spacing={1}>
            {routeSegments.map((segment, index) => (
              <Grid item xs={6} key={index}>
                <Chip
                  label={`${segment.segment}: ${segment.pace}`}
                  sx={{ width: '100%', fontSize: '10px', bgcolor: '#4CAF50', color: '#FFFFFF' }}
                />
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
